import ViewPDF from 'vue-pdf';
const pdfOperation = {
  data() {
    return {
      url: 'https://mozilla.github.io/pdf.js/web/compressed.tracemonkey-pldi-09.pdf',
      progress: 0,
      rotate: 0, // 角度
      pageTotal: 0, // 总页数
      currentPage: 1, // 当前页数
      pageRendering: false,
      scale: 100,
    }
  },
  mounted() {
    window.document.body.addEventListener('touchmove', (e) => {
      e.preventDefault()
    }, {
      passive: false
    });
  },
  components: {
    ViewPDF,
  },
  methods: {
    // pdf监听事件
    onProgress(val) { // 进度
      this.progress = Math.round((val || 0) * 100);
    },
    onPageLoaded(event) { // 当前页加载
      console.log('onPageLoaded', event);
      this.loading = false;
    },
    onNumPages(event) { // 获取总页数
      this.pageTotal = event;
    },
    onPdfError(err) {
      console.log(err);
    },
    // 上一页
    prevPage() {
      if (this.currentPage !== 1) {
        this.currentPage -= 1;
      }
    },
    // 下一页
    nextPage() {
      if (this.currentPage < this.pageTotal) {
        this.currentPage += 1;
      }
    },
    // 跳页
    jumpPage(page) {
      if (this.currentPage !== page) {
        this.currentPage = page;
      }
    },
    // 放大
    scaleGrow() {
        this.scale += 5;
        this.$refs.myPdfComponent.$el.style.width = parseInt(this.scale) + "%";
    },
    // 缩小
    scaleNarrow() {
      if (this.scale == 100) {
        return;
      }
      this.scale += -5;
      this.$refs.myPdfComponent.$el.style.width = parseInt(this.scale) + "%";
    },
    // 方向角度
    transformAngle() {
      this.rotate += 90;
      if (this.rotate === 360) {
        this.rotate = 0;
      }
    }
  },
};

export default pdfOperation