<template>
  <section id="app">
    <!-- 未创建房间 -->
    <section v-if="status < 2" class="">
      <h1 class="title">微信会议伴侣</h1>
      <p class="subtitle">免费生成演示共享链接，配合微信语音会议使用！</p>
      <div class="msgs" v-if="status === 1">
        <div class="msgs-item">
          <span class="msgs-item-label">创建时间</span>
          <div class="msgs-item-text">{{creationTime}}</div>
        </div>
        <div class="msgs-item">
          <span class="msgs-item-label">到期时间</span>
          <div class="msgs-item-text">24小时后自动删除 </div>
        </div>
        <div class="msgs-item">
          <span class="msgs-item-label">共享链接</span>
          <div class="msgs-item-text">
            <p>{{roomno.link}} 密码：{{roomno.password}}</p>
            <a @click="copyLink">复制链接及密码</a>
          </div>
        </div>
      </div>
    </section>
    <template v-if="status > 1 && status < 4">
      <ViewPDF
        ref="myPdfComponent"
        :src="url"
        :page="currentPage"
        :rotate="rotate"
        @progress="onProgress"
        @page-loaded="onPageLoaded"
        @num-pages="onNumPages"
        @error="onPdfError"
      />
    </template>
    <transition name="footer">
      <footer class="footer start" v-if="status < 1 && status > -1">
        <button class="button" :disabled="status === -1" @click="generate">生成共享链接</button>
      </footer>
    </transition>
    <transition name="footer">
      <footer class="footer button-group" v-if="status > 0">
        <button class="button" v-if="status === 1 || status === 3" @click="startRun">开始</button>
        <button class="button" v-if="status === 2 && currentPage < pageTotal" @click="stopRun">暂停</button>
        <button class="button" v-if="currentPage === pageTotal" @click="endRun">结束</button>
        <!-- <button class="button" @click="transformAngle">方向</button> -->
        <!-- <button class="button" @click="scaleGrow">放大</button> -->
        <!-- <button class="button" @click="scaleNarrow" :disabled="scale === 100">缩小</button> -->
        <button class="button" @click="prevPage" :disabled="currentPage === 1">上页</button>
        <button class="button" @click="nextPage" :disabled="currentPage === pageTotal">下页</button>
      </footer>
    </transition>
    <!-- 加载动画 -->
    <Loading :loading="loading" :progress="progress" />
  </section>
</template>

<script>
// import ReconnectingWebSocket from 'reconnecting-websocket';
import Loading from '@/components/Load';
import pdfOperation from '../pdfOperation';
import clipboard from '../clipboard';
/**
 * 获取当前时间 格式：yyyy-MM-dd HH:MM:SS
 */
function getCurrentTime() {
  var date = new Date();//当前时间
  var month = zeroFill(date.getMonth() + 1);//月
  var day = zeroFill(date.getDate());//日
  var hour = zeroFill(date.getHours());//时
  var minute = zeroFill(date.getMinutes());//分
  var second = zeroFill(date.getSeconds());//秒
  return `${date.getFullYear()}-${month}-${day} ${hour}:${minute}:${second}`;
}
/**
 * 补零
 */
function zeroFill(i){
  if (i >= 0 && i <= 9) {
      return "0" + i;
  } else {
      return i;
  }
}
export default {
  mixins: [pdfOperation],
  data() {
    return {
      status: -1, // 0：未创建；1：创建；2:开始直播；3：暂停直播；4：直播已结束
      loading: false,
      socket: null,
      roomno: {
        link: '',
        password: '',
      },
      creationTime: '',
    };
  },
  created() {
  },
  mounted() {
    this.updateStatus(0);
  },
  components: {
    Loading,
  },
  computed: {
  },
  watch: {
    currentPage() {
      this.startRun();
    }
  },
  methods: {
    // 生产共享链接
    generate() {
      const socket = new WebSocket('ws://wss.meeting.confmate.cn/ws/start');
      socket.onopen = this.onOpen;
      socket.onmessage = this.onMmessage;
      socket.onclose = this.onClose;
      socket.onerror = this.onError;
      this.socket = socket;
    },
    // 监听是否打开
    onOpen(event) {
      console.log(event)
    },
    // 监听关闭
    onClose() {
      this.status = 0;
      console.log('关闭了');
    },
    // 监听错误
    onError(event) {
      console.log('错误', event);
    },
    // 监听消息
    onMmessage({ data }) {
      if (this.status === 0) {
        const res = JSON.parse(data);
        console.log(res)
        this.roomno = {
          link: `http://llblh.com/subscribe?room=${res.Channel}`,
          room: res.Channel,
          password: res.Password,
        }
        this.creationTime = getCurrentTime();
        this.updateStatus(1);
      }
    },
    // 开始
    startRun() {
      const msg = {
        Success: true,
        ReceiveCount: 0,
        Type: 1, // 1：开始；2：暂停；3：结束
        Page: this.currentPage,
        Channel: this.roomno.room,
      }
      this.socket.send(JSON.stringify(msg));
      this.updateStatus(2);
    },
    // 暂停
    stopRun() {
      const msg = {
        Success: true,
        ReceiveCount: 0,
        Type: 2, // 1：开始；2：暂停；3：结束
        Page: this.currentPage,
        Channel: this.roomno.room,
      }
      this.socket.send(JSON.stringify(msg));
      this.updateStatus(3);
    },
    // 结束
    endRun() {
      const msg = {
        Success: true,
        ReceiveCount: 0,
        Type: 3, // 1：开始；2：暂停；3：结束
        Page: this.currentPage,
        Channel: this.roomno.room,
      }
      this.socket.send(JSON.stringify(msg));
      this.updateStatus(4);
      setTimeout(() => {
        this.socket.close();
      }, 1000);
    },
    // 更新状态
    updateStatus(status) {
      if (status === 2) {
        this.loading = true;
      }
      this.status = status;
    },
    // 复制链接
    copyLink(event) {
      const { roomno } = this;
      clipboard(`来我房间有惊喜${roomno.link}\n密码：${roomno.password}`, event, () => {
        alert('复制成功')
      }, () => {
        alert('请重新复制')
      });
    }
  },
};
</script>

